import{_ as t,o as a,c as o,a6 as s,bT as n}from"./chunks/framework.UYVGz2W_.js";const m=JSON.parse('{"title":"Custom Actions","description":"","frontmatter":{},"headers":[],"relativePath":"custom-actions/index.md","filePath":"custom-actions/index.md"}'),i={name:"custom-actions/index.md"};function c(r,e,l,u,h,p){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="custom-actions" tabindex="-1">Custom Actions <a class="header-anchor" href="#custom-actions" aria-label="Permalink to “Custom Actions”">​</a></h1><h2 id="what-are-custom-actions" tabindex="-1">What are Custom Actions? <a class="header-anchor" href="#what-are-custom-actions" aria-label="Permalink to “What are Custom Actions?”">​</a></h2><p>A custom action is a simple HTTP request that sends information from your current Kitsu selection to a custom endpoint. Essentially, when a user is in the Kitsu UI, they can send a request to another server containing the IDs of the selected elements.</p><h3 id="goal" tabindex="-1">Goal <a class="header-anchor" href="#goal" aria-label="Permalink to “Goal”">​</a></h3><p>The goal is to create an action outside of Kitsu (until a plugin system is available) without modifying the Kitsu/Zou core code. Essentially, it&#39;s a web request, usually a POST (but can be a GET) to a page or service you manage yourself. You catch the request and then perform an action with it.</p><p>Examples include:</p><ul><li>Debug page (displaying all accessible information for given objects, including field names, etc.)</li><li>Launch render in CGRU or Flamenco</li><li>Generate statistics pages for the APM</li><li>Create special playlists</li><li>Launch a custom protocol (with a service waiting for it) to start a video player, any DCC, etc.</li><li>Integrate with an asset manager like Kabaret to open it at the right spot or launch some actions</li></ul><p>Custom actions can be anything as long as you can catch the request (using, for example, a Python web server such as Flask or Tornado.web). They are designed to extend Kitsu to systems you control.</p><p>Useful information is provided to whatever catches the request, such as the current selection, the page you were on, the user who launched the action, etc. You can adapt the response based on the provided information.</p><p>Note that you can also run the custom action in the background (using an AJAX request instead of opening a new page) if you don&#39;t need to provide feedback to the user.</p><h2 id="how-to-setup-a-custom-action" tabindex="-1">How to Setup a Custom Action <a class="header-anchor" href="#how-to-setup-a-custom-action" aria-label="Permalink to “How to Setup a Custom Action”">​</a></h2><h3 id="creation" tabindex="-1">Creation <a class="header-anchor" href="#creation" aria-label="Permalink to “Creation”">​</a></h3><p>Only studio managers can set up a custom action. The custom action page is available in the right panel of the admin section.</p><p>When you have access to the custom action page, you can create a new action via the add button on the top right. The action creation requires four pieces of information:</p><p><img src="'+n+`" alt="Add Custom Action"></p><ul><li><strong>Name</strong>: The name of the action.</li><li><strong>URL</strong>: The target URL (we strongly recommend using the same domain as your Kitsu installation).</li><li><strong>Entity Type</strong>: For which kind of entity the custom action will be available.</li><li><strong>Use AJAX</strong>: Specify if the request must be sent as an AJAX request or as a form.</li></ul><p>Once your action is created, it will be accessible in the action top bar. When a user selects tasks in the asset or shot lists, by going to the <strong>Run custom action</strong> section, they will be able to execute the custom action for the current selection.</p><h3 id="data-sent-via-a-custom-action" tabindex="-1">Data Sent via a Custom Action <a class="header-anchor" href="#data-sent-via-a-custom-action" aria-label="Permalink to “Data Sent via a Custom Action”">​</a></h3><p>Data is sent in JSON format. It contains an object with the following fields:</p><ul><li><code>personid</code>: The ID of the user claiming the action.</li><li><code>personemail</code>: The email of the user claiming the action.</li><li><code>projectid</code>: The ID of the project of selected entities.</li><li><code>currentpath</code>: Current url path in Kitsu web application.</li><li><code>currentserver</code>: Host of the Kitsu sending the custom action.</li><li><code>selection</code>: List of selected task IDs.</li><li><code>entitytype</code>: Type of entities for which tasks are selected.</li></ul><p>Example:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;personid&quot;: &quot;b01bae1e-f829-458a-a1eb-131bb66628cc&quot;,</span></span>
<span class="line"><span>  &quot;personemail&quot;: &quot;admin@example.com&quot;,</span></span>
<span class="line"><span>  &quot;projectid&quot;: &quot;fa4d7f04-b8e0-4518-8dbc-2f24997ca76e&quot;,</span></span>
<span class="line"><span>  &quot;currentpath&quot;: &quot;/productions/fa4d7f04-b8e0-4518-8dbc-2f24997ca76e/assets&quot;,</span></span>
<span class="line"><span>  &quot;currentserver&quot;: &quot;localhost&quot;,</span></span>
<span class="line"><span>  &quot;selection&quot;: &quot;95c171e1-dfff-498f-93e3-548a739e3202&quot;,</span></span>
<span class="line"><span>  &quot;entitytype&quot;: &quot;asset&quot;</span></span>
<span class="line"><span>}</span></span></code></pre></div>`,22)])])}const f=t(i,[["render",c]]);export{m as __pageData,f as default};
